This produces incorrect verilog.  Not in the logic, per-se, but in the names being used by instances.

```  firrtl.circuit "SiFive_MulDiv" {
    firrtl.module @SiFive_MulDiv(in %clock: !firrtl.clock, in %reset: !firrtl.asyncreset, out %io_req_ready: !firrtl.uint<1>) {
      %c0_ui1 = firrtl.constant 0 : !firrtl.uint<1>
      %21 = firrtl.asUInt %reset : (!firrtl.asyncreset) -> !firrtl.uint<1>
      firrtl.assert %clock, %io_req_ready, %21, "blah"  {eventControl = 0 : i32, isConcurrent = true, name = "chisel3_builtin"}
      firrtl.connect %io_req_ready, %c0_ui1 : !firrtl.uint<1>, !firrtl.uint<1>
    }
}
